arguments.new_str:
using System;

class EnvVarCheck
{
    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        // .NET 9 breaking change: empty environment variables are now
        // supported and return "" instead of null. Previously both
        // "unset" and "empty" returned null; now they are distinct.
        var val = Environment.GetEnvironmentVariable("MY_FLAG");
        if (val == null)
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
        else if (val.Length == 0)
        {
            Console.WriteLine("MY_FLAG explicitly set to empty");
        }
    }
}

